          onDeletePart={(v) => {}} onDeleteAllParts={() => setDoc(doc(db,'settings','parts'), {data:[]})}
          onAddWorkplace={(v,t,x,y) => addDoc(collection(db,'workplaces'), {value:v, standardTime:t, coordX:x, coordY:y})}
